module up_down_counter (
    input Clk,
    input Reset,
    input UpDown,
    output reg [3:0] Q
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge Clk or posedge dbg_halt) begin
    if (Reset)
        Q <= 4'b0000;
    else if (UpDown)
        Q <= Q + 1;
    else
        Q <= Q - 1;
end

endmodule
